import "testing"

func TestParseUnitLabelForDrift(t *testing.T) {
	// Verify that pack-size parsing works for shrinkflation detection
	tests := []struct {
		name      string
		wantLabel string
		wantGrams int64
	}{
		{"Arroz Branco 5KG Premium", "KG", 5000},
		{"Azeite Extravirgem 500ML", "ML", 500},
		{"Leite UHT Integral 1L Caixinha", "L", 1000},
		{"Chocolate em Po 400G", "G", 400},
		{"Biscoito Recheado", "", 0},
	}
	for _, tc := range tests {
		label := parseUnitLabel(tc.name)
		grams := parsePackGrams(tc.name)
		if label != tc.wantLabel {
			t.Errorf("parseUnitLabel(%q) = %q, want %q", tc.name, label, tc.wantLabel)
		}
		if grams != tc.wantGrams {
			t.Errorf("parsePackGrams(%q) = %d, want %d", tc.name, grams, tc.wantGrams)
		}
	}
}

func TestShrinkflationDetection(t *testing.T) {
	// Unit inflation: same price, smaller pack → higher R$/kg
	oldPriceCents := int64(1000) // R$10.00
	oldGrams := int64(1000)      // 1KG
	newPriceCents := int64(1000) // R$10.00 (same price)
	newGrams := int64(800)       // 800g (smaller pack)

	oldRsPerKg := float64(oldPriceCents) / float64(oldGrams) * 10
	newRsPerKg := float64(newPriceCents) / float64(newGrams) * 10
	unitInflation := (newRsPerKg - oldRsPerKg) / oldRsPerKg * 100

	if unitInflation <= 0 {
		t.Errorf("expected positive unit inflation, got %f", unitInflation)
	}
	// 1000/1000*10 = 10 R$/kg, 1000/800*10 = 12.5 R$/kg → 25%% inflation
	expected := 25.0
	if unitInflation < expected-0.01 || unitInflation > expected+0.01 {
		t.Errorf("unit inflation = %f, want ~%f", unitInflation, expected)
	}
}
